-- Patchnote 0.7.5 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.7.5', 'patch', '2026-04-26T00:00:00.000Z',
  'Plugin install hotfix (CSP + bind-mount perms)',
  'Hotfix install plugin (CSP + permissions bind-mount)',
  '[{"type":"fix","titleEn":"Resolve plugin install URL server-side","titleFr":"Résolution de l''URL d''install plugin côté serveur","descEn":"0.7.4 added a frontend fetch to api.github.com to pick a Release asset over the source tarball, but the prod CSP blocks api.github.com from connect-src. The resolution moves to the backend (already trusted with GitHub calls for the update check), so the fix actually applies in prod. The /plugins/install endpoint accepts { repository } from the registry path and a raw { url } for manual installs.","descFr":"0.7.4 ajoutait un fetch frontend vers api.github.com pour préférer un asset de Release au tarball source, mais le CSP de prod bloque api.github.com sur connect-src. La résolution passe côté backend (déjà autorisé à parler à GitHub pour la check d''update), pour que le fix s''applique vraiment en prod. L''endpoint /plugins/install accepte { repository } pour le chemin registry et un { url } brut pour les installs manuels."},{"type":"fix","titleEn":"Auto-chown the plugins directory at boot","titleFr":"chown automatique du dossier plugins au boot","descEn":"Self-hosters with a host bind-mount for /app/packages/plugins (the docker-compose default) hit EACCES when Oscarr tried to mkdir the staging dir for an install — the host directory wasn''t owned by uid 1001 (the in-container oscarr user). The entrypoint now chowns + chmods 2775 (setgid) the plugins dir at boot, the same way it already handles /data, so files dropped by the host maintainer keep the right group and both sides can write.","descFr":"Les self-hosters avec un bind-mount host sur /app/packages/plugins (le défaut docker-compose) tombaient sur EACCES quand Oscarr tentait de mkdir le dossier de staging d''install — le dossier host n''était pas owné par l''uid 1001 (l''user oscarr du container). L''entrypoint fait maintenant chown + chmod 2775 (setgid) sur le dossier plugins au boot, comme il fait déjà pour /data, pour que les fichiers déposés par le mainteneur host gardent le bon groupe et que les deux côtés puissent écrire."}]'
) ON CONFLICT ("version") DO NOTHING;
